def main():
    print(f"Starting seed files generation for {len(PRIORITY_ACTS)} acts...")
    total_sections_count = 0
    
    # Ensure backend directory is clean and correct
    backend_dir = os.path.dirname(os.path.abspath(__file__))
    
    # Iterate and write files
    for idx, (act_code, act_name) in enumerate(PRIORITY_ACTS, 1):
        sections = build_act_sections(act_code, act_name)
        total_sections_count += len(sections)
        
        # Serialize the list of sections to clean python dictionary representation
        # Using json.dumps is safe and ensures valid python formatting
        laws_list_str = json.dumps(sections, indent=4, ensure_ascii=False)
        
        # Replace null/true/false for python equivalents
        laws_list_str = laws_list_str.replace("null", "None").replace("true", "True").replace("false", "False")
        
        # Format the template with the serialized sections list
        file_content = SCRIPT_TEMPLATE.format(laws_list=laws_list_str)
        
        # Resolve path to write (e.g. backend/seed_ipc.py, backend/seed_crpc.py)
        # Note: lowercase file names are cleaner e.g. seed_ipc.py
        file_name = f"seed_{act_code.lower()}.py"
        file_path = os.path.join(backend_dir, file_name)
        
        with open(file_path, "w", encoding="utf-8") as f:
            f.write(file_content)
            
        print(f"  [{idx:2d}/40] Generated {file_name} with {len(sections)} sections.")
        
    print(f"\nSUCCESS: Generated {len(PRIORITY_ACTS)} files with a total of {total_sections_count} sections.")

if __name__ == "__main__":
    main()
